  ChannelStripContent,
  ChannelStripFooter,
  ChannelStripHeader,
  ChannelStripSection,
  ChannelStripValue,
} from "@/components/audio/elements/channel-strip";
import { Transport } from "@/components/audio/elements/transport";

export function BlockChannelStripTransport() {
  return (
    <ChannelStrip aria-label="Transport" orientation="horizontal">
      <ChannelStripHeader>Track 1</ChannelStripHeader>
      <ChannelStripContent>
        <ChannelStripSection>
          <Transport
            aria-label="Seek"
            bufferedValue={62}
            onSeek={() => {
              //
            }}
            value={35}
          />
        </ChannelStripSection>
      </ChannelStripContent>
      <ChannelStripFooter>
        <ChannelStripValue>0:35 / 1:42</ChannelStripValue>
      </ChannelStripFooter>
    </ChannelStrip>
  );
}
